4528	func (s *Server) handleGraphQLQuery(w http.ResponseWriter, r *http.Request) {
4529		// Gate /graphql on the same localhost auth that protects every /api/*
4530		// handler. Without this, operators running `ddx server --addr 0.0.0.0`
4531		// ship an unauthenticated GraphQL endpoint serving bead data, worker
4532		// logs, mutations, and subscriptions. See opus final-gate review of
4533		// ddx-02d6142d and the scope line "isTrusted() is still the gatekeeper;
4534		// no auth bypass introduced".
4535		if !isTrusted(r) {
4536			writeJSON(w, http.StatusForbidden, map[string]string{"error": "graphql is localhost-only"})
4537			return
4538		}
4539		// Create gqlgen server with the DDX GraphQL schema
4540		gqlServer := handler.New(ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
4541			Resolvers: &ddxgraphql.Resolver{
4542				State:        s.state,
4543				WorkingDir:   s.WorkingDir,
4544				Workers:      s.workers,
4545				BeadBus:      s.beadHub,
4546				Actions:      &workerDispatchAdapter{manager: s.workers},
4547				ExecLogs:     &execLogAdapter{workingDir: s.WorkingDir},
4548				CoordMetrics: &coordMetricsAdapter{reg: s.workers.LandCoordinators},
4549			},
4550			Directives: ddxgraphql.DirectiveRoot{},
4551		}))
4552		gqlServer.AddTransport(transport.POST{})
4553		gqlServer.AddTransport(transport.GET{})
4554		gqlServer.AddTransport(transport.Websocket{
4555			Upgrader: websocket.Upgrader{
4556				CheckOrigin: func(r *http.Request) bool { return true },
4557			},
4558			KeepAlivePingInterval: 30 * time.Second,
4559		})
4560	
4561		gqlServer.ServeHTTP(w, r)
4562	}
